import React, { useState, useEffect } from "react";
import Sidebar from "../../../components/Admin/Sidebar";
import TopBar from "../../../components/Admin//TopBar";
import DataTable from "react-data-table-component";
import { Modal, Button } from "react-bootstrap";
import { useNavigate, Link, useParams } from "react-router-dom";
import {
    FaEye,
    FaTrashAlt,
    FaEllipsisV,
    FaBuilding,
    FaProjectDiagram,
    FaFolderOpen,
    FaFileAlt,
    FaTable,
} from "react-icons/fa";
import { FaArrowLeft } from "react-icons/fa";
import SuccessAlert from "../../../components/Admin/SuccessAlert";
import * as XLSX from "xlsx";
import { saveAs } from "file-saver";
import axios from "axios";
import { API_BASE_URL } from "../../../config/config";
function AdminCompanyList() {
    const navigate = useNavigate();
    const [isOpen, setIsOpen] = useState(false);
    const [show, setShow] = useState(false);
    const [successMessage, setsuccessMessage] = useState("");
    const toggleNavAdmin = () => {
        setIsOpen(!isOpen); // Toggle the state between true and false
    };

    const apiUrl = API_BASE_URL + "api/admin/company/";
    const [records, setRecords] = useState([]);
    const [UserName, setUserName] = useState(null);
    document.title = "All Companies - Admin";
    useEffect(() => {
        getallcompnay();
    }, []);
    const getallcompnay = async () => {
        let formData = {
            user_id: '',
        };
        try {
            const res = await axios.post(apiUrl + "getallcompnay", formData, {
                headers: {
                    Accept: "application/json",
                    "Content-Type": "application/json", // Ensure the content type is JSON
                },
            });
            var respo = res.data.results;
            console.log(respo)
            setRecords(respo);
        } catch (err) {
            // Enhanced error handling
            if (err.response) {
            } else if (err.request) {
                console.error("Request data:", err.request);
            } else {
                console.error("Error message:", err.message);
            }
        }
    };
    const [openDropdown, setOpenDropdown] = useState(null);

    const toggleDropdown = (id) => {
        // If the clicked row is already open, close it; otherwise open it
        setOpenDropdown(openDropdown === id ? null : id);
    };
    const columns = [
        {
            name: "Company Name",
            selector: (row) => row.company_name,
            sortable: true,
            className: "age",
        },
        {
            name: "Owner Name",
            selector: (row) => row.first_name + " " + row.last_name,
            sortable: true,
            className: "age",
        },
        {
            name: "Email",
            selector: (row) => row.company_email,
            sortable: true,
            className: "age",
        },
        {
            name: "Phone Number",
            selector: (row) => row.phone,
            sortable: true,
            className: "age",
        },
        {
            name: "Number of Employees",
            selector: (row) => row.employee_number,
            sortable: true,
            className: "age",
        },


        {
            name: "Actions",
            cell: (row) => (
                <div className="position-relative">
                    <button
                        className="block bg-transprent border-0"
                        onClick={() => toggleDropdown(row.id)}
                    >
                        <FaEllipsisV />
                    </button>

                    {openDropdown === row.id && (
                        <div
                            className="dropdown-menu show"
                            style={{
                                position: "absolute",
                                top: "calc(100% + 4px)",
                                right: 0,
                                minWidth: "200px",
                                zIndex: 9999,
                                borderRadius: "8px",
                                boxShadow:
                                    "0 4px 12px rgba(0, 0, 0, 0.1), 0 0 0 1px rgba(0, 0, 0, 0.05)",
                                backgroundColor: "#ffffff",
                                padding: "6px",
                                animation: "fadeInDown 0.2s ease-out",
                            }}
                        >




                            <Link
                                to={`/admin/company/profile/${row.id}`}
                                className="dropdown-item"
                                title="Company Profile"
                                style={{
                                    display: "flex",
                                    alignItems: "center",
                                    gap: "12px",
                                    padding: "10px 12px",
                                    fontSize: "14px",
                                    fontWeight: "500",
                                    color: "#374151",
                                    textDecoration: "none",
                                    borderRadius: "6px",
                                    transition: "all 0.15s ease",
                                    cursor: "pointer",
                                }}
                                onMouseEnter={(e) => {
                                    e.currentTarget.style.backgroundColor = "#f3f4f6";
                                    e.currentTarget.style.color = "#111827";
                                }}
                                onMouseLeave={(e) => {
                                    e.currentTarget.style.backgroundColor = "transparent";
                                    e.currentTarget.style.color = "#374151";
                                }}
                            >
                                <FaBuilding style={{ fontSize: "16px", color: "#3b82f6" }} />
                                <span>Company Profile</span>
                            </Link>


                            {/* Divider */}
                            <div
                                style={{
                                    height: "1px",
                                    backgroundColor: "#e5e7eb",
                                    margin: "6px 0",
                                }}
                            />

                            <button
                                type="button"
                                onClick={() => handleDelete(row.company_id)}
                                className="dropdown-item"
                                title="Delete Company"
                                style={{
                                    display: "flex",
                                    alignItems: "center",
                                    gap: "12px",
                                    padding: "10px 12px",
                                    fontSize: "14px",
                                    fontWeight: "500",
                                    color: "#dc2626",
                                    textDecoration: "none",
                                    borderRadius: "6px",
                                    transition: "all 0.15s ease",
                                    cursor: "pointer",
                                    border: "none",
                                    backgroundColor: "transparent",
                                    width: "100%",
                                    textAlign: "left",
                                }}
                                onMouseEnter={(e) => {
                                    e.currentTarget.style.backgroundColor = "#fef2f2";
                                    e.currentTarget.style.color = "#b91c1c";
                                }}
                                onMouseLeave={(e) => {
                                    e.currentTarget.style.backgroundColor = "transparent";
                                    e.currentTarget.style.color = "#dc2626";
                                }}
                            >
                                <FaTrashAlt style={{ fontSize: "16px" }} />
                                <span>Delete</span>
                            </button>
                        </div>
                    )}
                </div>
            ),
            ignoreRowClick: true,
            allowOverflow: true,
            button: true,
        },
    ];
    const [deleteId, setdeleteId] = useState("");
    const handleDelete = (id) => {
        setdeleteId(id);
        setShow(true);
    };
    const handleClose = () => {
        setShow(false);
    };
    const handleConfirmDelete = async () => {
        let formData = {
            id: deleteId,
        };
        try {
            const res = await axios.post(apiUrl + "deletecompany", formData, {
                headers: {
                    Accept: "application/json",
                    "Content-Type": "application/json", // Ensure the content type is JSON
                },
            });
            var respo = res.data;
            setShow(false);
            getallcompnay();
            setsuccessMessage(respo.message);
            setTimeout(() => {
                setsuccessMessage("");
            }, 1200); // 3
        } catch (err) {
            // Enhanced error handling
            if (err.response) {
            } else if (err.request) {
                console.error("Request data:", err.request);
            } else {
                console.error("Error message:", err.message);
            }
        }
    };
    const [searchQuery, setSearchQuery] = useState("");

    // Define filtered data based on the search query
    const filteredRecords = records.filter((record) =>
        Object.values(record)
            .join(" ")
            .toLowerCase()
            .includes(searchQuery.toLowerCase())
    );

    const handleexportdata = () => {
        if (!records.length) return;

        // Step 1: Prepare the data for export
        const exportData = records.map((row) => ({
            "Company Name": row.company_name,
            "Company Email": row.company_email,
            Industory: row.company_industory,
            "Phone Number": `${row.phone}`,
            "Company Website": row.company_website,
            "Number Of Employee": row.employee_number,
            "Years Of Registration": row.year_registration,
            "One-sentence headliner about the company": row.descriptionStep4,
            "What problem are you solving": row.problemStep4,
            "What is Your Solution to the Problem": row.solutionStep4,
            Street: row.company_street_address,
            Country: row.company_country,
            "State / Province / Territory / District": row.company_state,
            City: row.company_city,
            "Postal Code": row.company_postal_code,

            "Total Signatory": row.total_signatory,
        }));

        // Step 2: Create a worksheet and workbook
        const worksheet = XLSX.utils.json_to_sheet(exportData);
        const workbook = XLSX.utils.book_new();
        XLSX.utils.book_append_sheet(workbook, worksheet, "Companies");

        // Step 3: Write and download the file
        const excelBuffer = XLSX.write(workbook, {
            bookType: "xlsx",
            type: "array",
        });

        const data = new Blob([excelBuffer], {
            type: "application/vnd.openxmlformats-officedocument.spreadsheetml.sheet;charset=UTF-8",
        });

        saveAs(data, "company_export.xlsx");
    };

    const customStyles = {
        table: {
            style: {
                overflow: "visible !important",
                minWidth: "100%",
                boxShadow: "0px 3px 12px rgb(0 0 0 / 16%)",
                borderRadius: "12px",
            },
        },
        headCells: {
            style: {
                backgroundColor: "#efefef !important",
                fontWeight: "600",
                fontSize: "0.9rem",
                color: "#000 !important",
                whiteSpace: "nowrap",
            },
        },
        cells: {
            style: {
                whiteSpace: "nowrap",
                textOverflow: "ellipsis",
                backgroundColor: "#fff !important",
            },
        },
        rows: {
            style: {
                fontSize: "0.8rem",
                fontWeight: "500",
                "&:hover": {
                    backgroundColor: "#e8f0fe",
                },
            },
            stripedStyle: {
                backgroundColor: "#f4f6f8",
            },
        },
        pagination: {
            style: {
                backgroundColor: "#fafafa",
                padding: "12px 16px",
            },
        },
    };
    /* ── Action dropdown styles only ── */
    const actionStyles = `
  .au-action-btn {
    width: 32px;
    height: 32px;
    border: 1.5px solid #e2e8f0;
    background: #fff;
    border-radius: 8px;
    display: grid;
    place-items: center;
    cursor: pointer;
    color: #64748b;
    transition: background .15s, border-color .15s, color .15s;
    padding: 0;
  }
  .au-action-btn:hover {
    background: #f1f5f9;
    border-color: #cbd5e1;
    color: #0f172a;
  }
  .au-dropdown {
    position: fixed;
    min-width: 195px;
    background: #fff;
    border: 1px solid #e8edf2;
    border-radius: 12px;
    box-shadow: 0 8px 30px rgba(0,0,0,.13), 0 2px 8px rgba(0,0,0,.06);
    padding: 6px;
    z-index: 99999;
    animation: auFadeIn .15s ease-out;
  }
  @keyframes auFadeIn {
    from { opacity: 0; transform: translateY(-6px) scale(.97); }
    to   { opacity: 1; transform: translateY(0) scale(1); }
  }
  .au-drop-item {
    display: flex;
    align-items: center;
    gap: 10px;
    padding: 9px 12px;
    border-radius: 8px;
    font-size: 0.84rem;
    font-weight: 500;
    color: #334155;
    cursor: pointer;
    text-decoration: none !important;
    border: none;
    background: transparent;
    width: 100%;
    font-family: inherit;
    transition: background .12s, color .12s;
    line-height: 1;
  }
  .au-drop-item:hover {
    background: #f1f5f9;
    color: #0f172a;
    text-decoration: none !important;
  }
  .au-drop-item.danger { color: #dc2626; }
  .au-drop-item.danger:hover { background: #fef2f2; color: #b91c1c; }
  .au-drop-item svg { font-size: 13px; flex-shrink: 0; }
  .au-drop-divider { height: 1px; background: #f1f5f9; margin: 5px 6px; }
`;
    return (
        <>
            <style>{actionStyles}</style>
            <div>
                <div className="d-flex align-items-start gap-0">
                    <Sidebar />
                    <div className="d-flex flex-column gap-0 w-100 dashboard_padding">
                        <TopBar />
                        <section className="dashboard_adminh">
                            <div className="container-xl">
                                <div className="row gy-4">
                                    <div className="col-12">
                                        <div className="card p-3">
                                            {successMessage && (
                                                <SuccessAlert
                                                    message={successMessage}
                                                    onClose={() => setsuccessMessage("")}
                                                />
                                            )}
                                            <div className="d-flex justify-content-between gap-2 flex-wrap mb-2">

                                                <h5 className="mb-4">All Companies</h5>
                                            </div>

                                            <div className="d-flex justify-content-between flex-wrap gap-3 pb-3 align-items-center">
                                                <div className="d-flex justify-content-end flex-wrap  align-items-end">
                                                    <div class="search-bar">
                                                        <input
                                                            type="text"
                                                            placeholder="Search by name or email..."
                                                            value={searchQuery}
                                                            onChange={(e) => setSearchQuery(e.target.value)}
                                                        />
                                                        <span class="search-icon">
                                                            <svg
                                                                xmlns="http://www.w3.org/2000/svg"
                                                                fill="none"
                                                                viewBox="0 0 24 24"
                                                                stroke="currentColor"
                                                            >
                                                                <path
                                                                    stroke-linecap="round"
                                                                    stroke-linejoin="round"
                                                                    stroke-width="2"
                                                                    d="M21 21l-4.35-4.35M17 11a6 6 0 11-12 0 6 6 0 0112 0z"
                                                                />
                                                            </svg>
                                                        </span>
                                                    </div>
                                                </div>
                                                <button
                                                    type="button"
                                                    onClick={handleexportdata}
                                                    className="admin_btn"
                                                >
                                                    Export to Excel
                                                </button>
                                            </div>
                                            <div className="d-flex  flex-column justify-content-between align-items-start tb-box">
                                                <style>
                                                    {`
                                                    .datatb-report {
                                                    overflow: visible !important;
                                                    }
                                                    .au-table-scroll {
                                                    width: 100%;
                                                    overflow-x: auto;
                                                    -webkit-overflow-scrolling: touch;
                                                    }
                                                    @media (max-width: 768px) {
                                                    .au-table-scroll .rdt_Table {
                                                        min-width: 650px;
                                                    }
                                                    }
                                                `}
                                                </style>
                                                <DataTable
                                                    columns={columns}
                                                    data={filteredRecords}
                                                    pagination
                                                    highlightOnHover
                                                    striped
                                                    responsive
                                                    customStyles={customStyles}
                                                    className="custom-scrollbar datatb-report"
                                                    paginationPerPage={10}
                                                    paginationRowsPerPageOptions={[10, 25, 50, 100]}
                                                    paginationComponentOptions={{
                                                        rowsPerPageText: "Rows per page:",
                                                        rangeSeparatorText: "of",
                                                        noRowsPerPage: false,
                                                        selectAllRowsItem: false,
                                                    }}
                                                    noDataComponent={
                                                        <div
                                                            style={{
                                                                padding: "48px 24px",
                                                                textAlign: "center",
                                                                color: "#6b7280",
                                                                fontSize: "14px",
                                                            }}
                                                        >
                                                            <div
                                                                style={{
                                                                    fontSize: "48px",
                                                                    marginBottom: "12px",
                                                                    opacity: 0.3,
                                                                }}
                                                            >
                                                                📋
                                                            </div>
                                                            <p style={{ margin: 0, fontWeight: 500 }}>
                                                                No record found
                                                            </p>
                                                            <p
                                                                style={{
                                                                    margin: "4px 0 0 0",
                                                                    fontSize: "13px",
                                                                    color: "#9ca3af",
                                                                }}
                                                            >
                                                                Try adjusting your search or filters
                                                            </p>
                                                        </div>
                                                    }
                                                />
                                            </div>
                                        </div>
                                    </div>
                                </div>
                            </div>
                        </section>
                    </div>
                </div>
            </div>
            <Modal show={show} onHide={handleClose}>
                <Modal.Header closeButton>
                    <Modal.Title>Confirm Deletion</Modal.Title>
                </Modal.Header>
                <Modal.Body>
                    <p>
                        Are you sure you want to delete this record? This action will
                        permanently delete all associated data and cannot be undone.
                    </p>
                </Modal.Body>
                <Modal.Footer>
                    <Button variant="secondary" onClick={handleClose}>
                        Cancel
                    </Button>
                    <Button variant="danger" onClick={handleConfirmDelete}>
                        Confirm Delete
                    </Button>
                </Modal.Footer>
            </Modal>
        </>
    );
}
<style jsx>{`
  @keyframes fadeInDown {
    from {
      opacity: 0;
      transform: translateY(-8px);
    }
    to {
      opacity: 1;
      transform: translateY(0);
    }
  }
`}</style>;
export default AdminCompanyList;
